// TestTopLevelBlocks verifies that top-level blocks match the spec
func TestTopLevelBlocks(t *testing.T) {
	rootSchema := std[""]
	require.NotNil(t, rootSchema)

	expectedBlocks := []string{
		"resource",    // Create a resource (spec section)
		"resources",   // Create list of resources (spec section)
		"group",       // Groups of resources (spec section)
		"locals",      // Local variables (spec section)
		"composite",   // Write composite status/connection (spec section)
		"context",     // Write to context (spec section)
		"requirement", // Extra resources requirements (spec section)
		"function",    // User-defined functions (spec section)
	}

	for _, blockType := range expectedBlocks {
		assert.Contains(t, rootSchema.NestedBlocks, blockType,
			"Top level should support %s block per spec", blockType)
	}
}

// TestResourceBlockSchema verifies resource block schema per spec
func TestResourceBlockSchema(t *testing.T) {
	resourceSchema := std["resource"]
	require.NotNil(t, resourceSchema, "resource block should have schema")

	// Per spec: resource blocks should have body attribute
	assert.Contains(t, resourceSchema.Attributes, "body",
		"resource block should have 'body' attribute per spec")

	// Per spec: resource blocks support condition attribute
	assert.Contains(t, resourceSchema.Attributes, "condition",
		"resource block should support 'condition' attribute per spec")

	// Condition should be boolean and optional
	condAttr := resourceSchema.Attributes["condition"]
	assert.True(t, condAttr.IsOptional, "condition should be optional per spec")

	// Per spec: resource blocks can have nested blocks
	expectedNested := []string{"locals", "composite", "context", "ready"}
	for _, nested := range expectedNested {
		assert.Contains(t, resourceSchema.NestedBlocks, nested,
			"resource block should support %s nested block per spec", nested)
	}
}

// TestResourcesBlockSchema verifies resources (collection) block schema per spec
