	resourcesSchema := std["resources"]
	require.NotNil(t, resourcesSchema, "resources block should have schema")

	// Per spec: resources blocks must have for_each
	assert.Contains(t, resourcesSchema.Attributes, "for_each",
		"resources block must have 'for_each' attribute per spec")
	forEachAttr := resourcesSchema.Attributes["for_each"]
	assert.False(t, forEachAttr.IsOptional,
		"for_each should be required per spec")

	// Per spec: resources blocks should have optional name attribute
