// TestSelectBlockSchema verifies select block schema per spec
func TestSelectBlockSchema(t *testing.T) {
	selectSchema := std["select"]
	require.NotNil(t, selectSchema, "select block should have schema")

	// Per spec: select blocks must have apiVersion and kind
	assert.Contains(t, selectSchema.Attributes, "apiVersion",
		"select block must have 'apiVersion' attribute per spec")
	assert.Contains(t, selectSchema.Attributes, "kind",
		"select block must have 'kind' attribute per spec")

	apiVersionAttr := selectSchema.Attributes["apiVersion"]
	kindAttr := selectSchema.Attributes["kind"]

	assert.True(t, apiVersionAttr.IsRequired, "apiVersion should be required per spec")
	assert.True(t, kindAttr.IsRequired, "kind should be required per spec")

	// Per spec: select blocks can have matchName or matchLabels (optional)
	assert.Contains(t, selectSchema.Attributes, "matchName",
		"select block should have 'matchName' attribute per spec")
	assert.Contains(t, selectSchema.Attributes, "matchLabels",
		"select block should have 'matchLabels' attribute per spec")

	matchNameAttr := selectSchema.Attributes["matchName"]
	matchLabelsAttr := selectSchema.Attributes["matchLabels"]

	assert.True(t, matchNameAttr.IsOptional, "matchName should be optional per spec")
	assert.True(t, matchLabelsAttr.IsOptional, "matchLabels should be optional per spec")

	// Verify correct descriptions (Bug #2 fix verification)
	assert.Contains(t, matchNameAttr.Description.Value(), "name",
		"matchName description should mention 'name'")
	assert.Contains(t, matchLabelsAttr.Description.Value(), "labels",
		"matchLabels description should mention 'labels'")
}

