	assert.Contains(t, resourceSchema.NestedBlocks, "ready",
		"resource block should support 'ready' nested block per spec")

	templateSchema := std["template"]
	assert.Contains(t, templateSchema.NestedBlocks, "ready",
		"template block should support 'ready' nested block per spec")

	// Per spec: ready block must have its own schema with value attribute
	readySchema := std["ready"]
	require.NotNil(t, readySchema, "ready block must have schema definition")

	// Per spec: ready block must have value attribute
	assert.Contains(t, readySchema.Attributes, "value",
		"ready block must have 'value' attribute per spec")

