// TestBasicK8sObjectSchema verifies the basic K8s object schema
func TestBasicK8sObjectSchema(t *testing.T) {
	k8sObj := basicK8sObjectSchema()

	// Should have required apiVersion and kind
	assert.Contains(t, k8sObj.Attributes, "apiVersion")
	assert.Contains(t, k8sObj.Attributes, "kind")
	assert.Contains(t, k8sObj.Attributes, "metadata")

	apiVersionAttr := k8sObj.Attributes["apiVersion"]
	kindAttr := k8sObj.Attributes["kind"]

	assert.True(t, apiVersionAttr.IsRequired, "apiVersion should be required")
	assert.True(t, kindAttr.IsRequired, "kind should be required")

	// Metadata should be optional object
	metadataAttr := k8sObj.Attributes["metadata"]
	assert.True(t, metadataAttr.IsOptional, "metadata should be optional")

	// Metadata should have name, namespace, labels, annotations
	metadataObj, ok := metadataAttr.Constraint.(schema.Object)
	require.True(t, ok, "metadata should be an object")

	assert.Contains(t, metadataObj.Attributes, "name")
	assert.Contains(t, metadataObj.Attributes, "generateName")
	assert.Contains(t, metadataObj.Attributes, "namespace")
	assert.Contains(t, metadataObj.Attributes, "labels")
	assert.Contains(t, metadataObj.Attributes, "annotations")
}

// TestWithoutStatus verifies WithoutStatus removes status attribute
func TestWithoutStatus(t *testing.T) {
	tests := []struct {
		name             string
		input            *schema.AttributeSchema
		shouldHaveStatus bool
	}{
		{
			name:             "nil schema",
			input:            nil,
			shouldHaveStatus: false,
		},
		{
			name: "non-object constraint",
			input: &schema.AttributeSchema{
				Constraint: schema.String{},
			},
			shouldHaveStatus: false,
		},
		{
			name: "object without status",
			input: &schema.AttributeSchema{
				Constraint: schema.Object{
					Attributes: map[string]*schema.AttributeSchema{
						"spec": {IsOptional: true},
					},
				},
			},
			shouldHaveStatus: false,
		},
		{
			name: "object with status",
			input: &schema.AttributeSchema{
				Constraint: schema.Object{
					Attributes: map[string]*schema.AttributeSchema{
						"spec":   {IsOptional: true},
						"status": {IsOptional: true},
					},
				},
			},
			shouldHaveStatus: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := WithoutStatus(tt.input)

			if tt.input == nil {
				assert.Nil(t, result)
				return
			}

			if !tt.shouldHaveStatus {
				// Result should be same as input
				assert.Equal(t, tt.input, result)
				return
			}

			// Should have removed status
			obj, ok := result.Constraint.(schema.Object)
			require.True(t, ok)
			assert.NotContains(t, obj.Attributes, "status")
			assert.Contains(t, obj.Attributes, "spec")

			// Original should be unchanged
			origObj, _ := tt.input.Constraint.(schema.Object)
			assert.Contains(t, origObj.Attributes, "status")
		})
	}
}

// TestWithStatusOnly verifies WithStatusOnly keeps only status attribute
func TestWithStatusOnly(t *testing.T) {
	tests := []struct {
		name             string
		input            *schema.AttributeSchema
		shouldHaveStatus bool
	}{
		{
			name:             "nil schema",
			input:            nil,
			shouldHaveStatus: false,
		},
		{
			name: "non-object constraint",
			input: &schema.AttributeSchema{
				Constraint: schema.String{},
			},
			shouldHaveStatus: false,
		},
		{
			name: "object without status",
			input: &schema.AttributeSchema{
				Constraint: schema.Object{
					Attributes: map[string]*schema.AttributeSchema{
						"spec": {IsOptional: true},
					},
				},
			},
			shouldHaveStatus: false,
		},
		{
			name: "object with status and spec",
			input: &schema.AttributeSchema{
				Constraint: schema.Object{
					Attributes: map[string]*schema.AttributeSchema{
						"spec":   {IsOptional: true},
						"status": {IsOptional: true},
					},
				},
			},
			shouldHaveStatus: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := WithStatusOnly(tt.input)

			if tt.input == nil {
				assert.Nil(t, result)
				return
			}

			if !tt.shouldHaveStatus {
				// Result should be same as input
				assert.Equal(t, tt.input, result)
				return
			}

			// Should have only status
			obj, ok := result.Constraint.(schema.Object)
			require.True(t, ok)
			assert.Contains(t, obj.Attributes, "status")
			assert.NotContains(t, obj.Attributes, "spec")
			assert.Len(t, obj.Attributes, 1)

			// Original should be unchanged
			origObj, _ := tt.input.Constraint.(schema.Object)
			assert.Contains(t, origObj.Attributes, "status")
			assert.Contains(t, origObj.Attributes, "spec")
		})
	}
}

// TestWithoutAPIVersionAndKind verifies removal of apiVersion and kind
func TestWithoutAPIVersionAndKind(t *testing.T) {
	tests := []struct {
		name  string
		input *schema.AttributeSchema
		want  []string // attributes that should remain
	}{
		{
			name:  "nil schema",
			input: nil,
			want:  nil,
		},
		{
			name: "non-object constraint",
			input: &schema.AttributeSchema{
				Constraint: schema.String{},
			},
			want: []string{},
		},
		{
			name: "object with apiVersion, kind, and others",
			input: &schema.AttributeSchema{
				Constraint: schema.Object{
					Attributes: map[string]*schema.AttributeSchema{
						"apiVersion": {IsRequired: true},
						"kind":       {IsRequired: true},
						"spec":       {IsOptional: true},
						"metadata":   {IsOptional: true},
					},
				},
			},
			want: []string{"spec", "metadata"},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := WithoutAPIVersionAndKind(tt.input)

			if tt.input == nil {
				assert.Nil(t, result)
				return
			}

			obj, ok := result.Constraint.(schema.Object)
			if !ok {
				assert.Equal(t, tt.input, result)
				return
			}

			assert.NotContains(t, obj.Attributes, "apiVersion")
			assert.NotContains(t, obj.Attributes, "kind")

			for _, attr := range tt.want {
				assert.Contains(t, obj.Attributes, attr)
			}
		})
	}
}

