// TestDependentSchemaOrDefault verifies DependentSchemaOrDefault function
func TestDependentSchemaOrDefault(t *testing.T) {
	mockSchema := &schema.AttributeSchema{
		Constraint: schema.Object{
			Attributes: map[string]*schema.AttributeSchema{
				"spec": {IsOptional: true},
			},
		},
	}

	tests := []struct {
		name         string
		source       string
		dyn          DynamicLookup
		expectCustom bool
	}{
		{
			name: "returns custom schema when dependentSchema succeeds",
			source: `resource "test" {
				body = {
					apiVersion = "v1"
					kind = "Pod"
				}
			}`,
			dyn: &mockDynamicLookup{
				schemas: map[string]map[string]*schema.AttributeSchema{
					"v1": {"Pod": mockSchema},
				},
			},
			expectCustom: true,
		},
		{
			name: "returns default schema when no body attribute",
			source: `resource "test" {
			}`,
			dyn:          &mockDynamicLookup{},
			expectCustom: false,
		},
		{
			name: "returns default schema when body is list",
			source: `resource "test" {
				body = ["item1", "item2"]
			}`,
			dyn:          &mockDynamicLookup{},
			expectCustom: false,
		},
		{
			name: "returns default schema when missing apiVersion",
			source: `resource "test" {
				body = {
					kind = "Pod"
				}
			}`,
			dyn:          &mockDynamicLookup{},
			expectCustom: false,
		},
		{
			name: "returns default schema when missing kind",
			source: `resource "test" {
				body = {
					apiVersion = "v1"
				}
			}`,
			dyn:          &mockDynamicLookup{},
			expectCustom: false,
		},
		{
			name: "returns default schema when no matching schema in lookup",
			source: `resource "test" {
				body = {
					apiVersion = "v1"
					kind = "Unknown"
				}
			}`,
			dyn:          &mockDynamicLookup{},
			expectCustom: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			file, diags := hclsyntax.ParseConfig([]byte(tt.source), "test.hcl", hcl.InitialPos)
			require.False(t, diags.HasErrors(), "parse should succeed")

			var block *hclsyntax.Block
			for _, b := range file.Body.(*hclsyntax.Body).Blocks {
				if b.Type == "resource" {
					block = b
					break
				}
			}
			require.NotNil(t, block, "should find resource block")

			result := DependentSchemaOrDefault(tt.dyn, block)

			require.NotNil(t, result, "should always return a schema")

			if tt.expectCustom {
				// Should return the custom schema
				obj, ok := result.Constraint.(schema.Object)
				require.True(t, ok, "should be object constraint")
				assert.Contains(t, obj.Attributes, "spec", "should have custom schema attributes")
			} else {
				// Should return basicBodyAttributeSchema (default K8s object)
				obj, ok := result.Constraint.(schema.Object)
				require.True(t, ok, "should be object constraint")
				assert.Contains(t, obj.Attributes, "apiVersion", "should have basic K8s object schema")
				assert.Contains(t, obj.Attributes, "kind", "should have basic K8s object schema")
			}
		})
	}
}

