// TestConditionAttributes verifies all blocks that should support conditions do
func TestConditionAttributes(t *testing.T) {
	// Per spec: these blocks support condition attribute
	blocksWithCondition := []string{
		"resource", "resources", "group", "requirement",
	}

	for _, blockType := range blocksWithCondition {
		t.Run(blockType, func(t *testing.T) {
			blockSchema := std[blockType]
			require.NotNil(t, blockSchema, "%s should have schema", blockType)

			assert.Contains(t, blockSchema.Attributes, "condition",
				"%s should support 'condition' attribute per spec", blockType)

			condAttr := blockSchema.Attributes["condition"]
			assert.True(t, condAttr.IsOptional,
				"condition should be optional in %s per spec", blockType)

			// Condition should be boolean
			assert.EqualValues(t, schema.Bool{}, condAttr.Constraint,
				"condition should be boolean per spec")
		})
	}
}

// TestFunctionSignatures verifies function signatures are complete
func TestFunctionSignatures(t *testing.T) {
	funcs := stdFunctions()

	// Sample some functions to ensure they have proper signatures
	tests := []struct {
		name        string
		paramCount  int
		hasVarParam bool
	}{
		{"abs", 1, false},
		{"base64encode", 1, false},
		{"can", 1, false},
		{"concat", 0, true}, // variadic
		{"format", 1, true}, // format string + variadic args
		{"try", 0, true},    // variadic
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			sig, ok := funcs[tt.name]
			require.True(t, ok, "function %s should exist", tt.name)

			assert.Len(t, sig.Params, tt.paramCount,
				"function %s should have %d params", tt.name, tt.paramCount)

			if tt.hasVarParam {
				assert.NotNil(t, sig.VarParam,
					"function %s should have variadic param", tt.name)
			} else {
				assert.Nil(t, sig.VarParam,
					"function %s should not have variadic param", tt.name)
			}

			assert.NotEmpty(t, sig.Description,
				"function %s should have description", tt.name)
		})
	}
}
